/**
 * Notification log model — tracks sent notification history.
 *
 * Every notification dispatched by NotificationService is recorded as a
 * NotificationLogEntry for auditing and querying purposes.
 */

import type { NotificationChannel, NotificationType } from './notification.js';

export type DeliveryStatus = 'sent' | 'failed';

export interface NotificationLogEntry {
  id: string;
  recipient: string;
  channel: NotificationChannel;
  notificationType: NotificationType;
  subject: string;
  body: string;
  status: DeliveryStatus;
  timestamp: Date;
  metadata?: Record<string, string>;
}

export interface NotificationLogQuery {
  userId?: string;
  recipient?: string;
  channel?: NotificationChannel;
  notificationType?: NotificationType;
  status?: DeliveryStatus;
  startDate?: Date;
  endDate?: Date;
}

/**
 * Repository for notification log entries.
 *
 * Extends BaseRepository with query methods for filtering notification
 * history by recipient, channel, type, status, and date range.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';
import type { NotificationLogEntry, DeliveryStatus, NotificationLogQuery } from '../models/notification-log.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLogEntry> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLogEntry {
    return {
      id: record['id'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      notificationType: record['notificationType'] as NotificationType,
      subject: record['subject'] as string,
      body: record['body'] as string,
      status: record['status'] as DeliveryStatus,
      timestamp: new Date(record['timestamp'] as string),
      metadata: record['metadata']
        ? (JSON.parse(record['metadata'] as string) as Record<string, string>)
        : undefined,
    };
  }

  protected toRecord(entity: NotificationLogEntry): DatabaseRecord {
    return {
      id: entity.id,
      recipient: entity.recipient,
      channel: entity.channel,
      notificationType: entity.notificationType,
      subject: entity.subject,
      body: entity.body,
      status: entity.status,
      timestamp: entity.timestamp.toISOString(),
      metadata: entity.metadata ? JSON.stringify(entity.metadata) : undefined,
    };
  }

  findByRecipient(recipient: string): NotificationLogEntry[] {
    return this.findAll((entry) => entry.recipient === recipient);
  }

  findByUserId(userId: string): NotificationLogEntry[] {
    return this.findAll((entry) => entry.metadata?.['userId'] === userId);
  }

  findByChannel(channel: NotificationChannel): NotificationLogEntry[] {
    return this.findAll((entry) => entry.channel === channel);
  }

  findByType(notificationType: NotificationType): NotificationLogEntry[] {
    return this.findAll((entry) => entry.notificationType === notificationType);
  }

  findByStatus(status: DeliveryStatus): NotificationLogEntry[] {
    return this.findAll((entry) => entry.status === status);
  }

  query(q: NotificationLogQuery): NotificationLogEntry[] {
    return this.findAll((entry) => {
      if (q.recipient && entry.recipient !== q.recipient) return false;
      if (q.userId && entry.metadata?.['userId'] !== q.userId) return false;
      if (q.channel && entry.channel !== q.channel) return false;
      if (q.notificationType && entry.notificationType !== q.notificationType) return false;
      if (q.status && entry.status !== q.status) return false;
      if (q.startDate && entry.timestamp < q.startDate) return false;
      if (q.endDate && entry.timestamp > q.endDate) return false;
      return true;
    });
  }
}

/**
 * Notification history service — logs and queries sent notifications.
 *
 * Integrated with NotificationService: every dispatched notification is
 * recorded via logNotification(). Provides query methods for retrieving
 * notification history by user, type, channel, status, and date range.
 */

import type { Notification } from '../models/notification.js';
import type { NotificationLogEntry, NotificationLogQuery } from '../models/notification-log.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
}

export function resetNotificationLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private logRepository: NotificationLogRepository) {}

  logNotification(notification: Notification): NotificationLogEntry {
    const entry: NotificationLogEntry = {
      id: generateLogId(),
      recipient: notification.recipient,
      channel: notification.channel,
      notificationType: notification.notificationType,
      subject: notification.subject,
      body: notification.body,
      status: notification.status,
      timestamp: notification.sentAt,
      metadata: notification.metadata,
    };

    this.logRepository.save(entry);
    this.logger.info(`Logged notification ${notification.id} as ${entry.id}`);
    return entry;
  }

  updateStatus(logId: string, status: 'sent' | 'failed'): NotificationLogEntry {
    return this.logRepository.update(logId, { status });
  }

  getByUser(userId: string): NotificationLogEntry[] {
    return this.logRepository.findByUserId(userId);
  }

  getByRecipient(recipient: string): NotificationLogEntry[] {
    return this.logRepository.findByRecipient(recipient);
  }

  getByType(notificationType: NotificationLogEntry['notificationType']): NotificationLogEntry[] {
    return this.logRepository.findByType(notificationType);
  }

  getByChannel(channel: NotificationLogEntry['channel']): NotificationLogEntry[] {
    return this.logRepository.findByChannel(channel);
  }

  getByDateRange(startDate: Date, endDate: Date): NotificationLogEntry[] {
    return this.logRepository.query({ startDate, endDate });
  }

  query(q: NotificationLogQuery): NotificationLogEntry[] {
    return this.logRepository.query(q);
  }

  getAll(): NotificationLogEntry[] {
    return this.logRepository.findAll();
  }

  getCount(): number {
    return this.logRepository.count();
  }
}

