import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetNotificationLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailNotificationAdapter, InMemoryEmailTransport } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';
import type { Notification } from '../../src/models/notification.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let logRepo: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    logRepo = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(logRepo);
    resetNotificationLogIdCounter();
  });

  function makeNotification(overrides?: Partial<Notification>): Notification {
    return {
      id: 'notif-0001',
      recipient: 'alice@example.com',
      subject: 'Order Confirmation: order-1',
      body: 'Your order has been placed.',
      channel: 'email',
      notificationType: 'order_confirmation',
      status: 'sent',
      sentAt: new Date('2026-01-15T10:00:00Z'),
      metadata: { orderId: 'order-1', userId: 'user-1' },
      ...overrides,
    };
  }

  describe('logNotification', () => {
    it('should log a notification and return the log entry', () => {
      const notification = makeNotification();
      const entry = historyService.logNotification(notification);

      expect(entry.id).toBe('nlog-0001');
      expect(entry.recipient).toBe('alice@example.com');
      expect(entry.channel).toBe('email');
      expect(entry.notificationType).toBe('order_confirmation');
      expect(entry.subject).toBe('Order Confirmation: order-1');
      expect(entry.body).toBe('Your order has been placed.');
      expect(entry.status).toBe('sent');
      expect(entry.timestamp).toEqual(new Date('2026-01-15T10:00:00Z'));
      expect(entry.metadata).toEqual({ orderId: 'order-1', userId: 'user-1' });
    });

    it('should generate sequential IDs', () => {
      const e1 = historyService.logNotification(makeNotification({ id: 'notif-0001' }));
      const e2 = historyService.logNotification(makeNotification({ id: 'notif-0002' }));

      expect(e1.id).toBe('nlog-0001');
      expect(e2.id).toBe('nlog-0002');
    });

    it('should persist entries in the repository', () => {
      historyService.logNotification(makeNotification());
      expect(historyService.getCount()).toBe(1);
    });
  });

  describe('updateStatus', () => {
    it('should update the status of a log entry', () => {
      const entry = historyService.logNotification(makeNotification());
      const updated = historyService.updateStatus(entry.id, 'failed');

      expect(updated.status).toBe('failed');
    });
  });

  describe('query by user', () => {
    it('should return entries for a specific userId from metadata', () => {
      historyService.logNotification(makeNotification({ metadata: { userId: 'user-1' } }));
      historyService.logNotification(makeNotification({ id: 'notif-0002', metadata: { userId: 'user-2' } }));
      historyService.logNotification(makeNotification({ id: 'notif-0003', metadata: { userId: 'user-1' } }));

      const results = historyService.getByUser('user-1');
      expect(results).toHaveLength(2);
      expect(results.every((e) => e.metadata?.['userId'] === 'user-1')).toBe(true);
    });

    it('should return empty array for unknown user', () => {
      historyService.logNotification(makeNotification());
      expect(historyService.getByUser('unknown')).toHaveLength(0);
    });
  });

  describe('query by recipient', () => {
    it('should return entries for a specific recipient', () => {
      historyService.logNotification(makeNotification({ recipient: 'alice@example.com' }));
      historyService.logNotification(makeNotification({ id: 'notif-0002', recipient: 'bob@example.com' }));

      const results = historyService.getByRecipient('alice@example.com');
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('alice@example.com');
    });
  });

  describe('query by type', () => {
    it('should return entries for a specific notification type', () => {
      historyService.logNotification(makeNotification({ notificationType: 'order_confirmation' }));
      historyService.logNotification(
        makeNotification({ id: 'notif-0002', notificationType: 'order_status_update' }),
      );
      historyService.logNotification(
        makeNotification({ id: 'notif-0003', notificationType: 'order_confirmation' }),
      );

      const results = historyService.getByType('order_confirmation');
      expect(results).toHaveLength(2);
    });
  });

  describe('query by channel', () => {
    it('should return entries for a specific channel', () => {
      historyService.logNotification(makeNotification({ channel: 'email' }));
      historyService.logNotification(makeNotification({ id: 'notif-0002', channel: 'webhook' }));

      expect(historyService.getByChannel('email')).toHaveLength(1);
      expect(historyService.getByChannel('webhook')).toHaveLength(1);
    });
  });

  describe('query by date range', () => {
    it('should return entries within a date range', () => {
      historyService.logNotification(
        makeNotification({ sentAt: new Date('2026-01-10T00:00:00Z') }),
      );
      historyService.logNotification(
        makeNotification({ id: 'notif-0002', sentAt: new Date('2026-01-20T00:00:00Z') }),
      );
      historyService.logNotification(
        makeNotification({ id: 'notif-0003', sentAt: new Date('2026-02-01T00:00:00Z') }),
      );

      const results = historyService.getByDateRange(
        new Date('2026-01-15T00:00:00Z'),
        new Date('2026-01-25T00:00:00Z'),
      );
      expect(results).toHaveLength(1);
      expect(results[0]?.id).toBe('nlog-0002');
    });
  });

  describe('combined query', () => {
    it('should filter by multiple criteria', () => {
      historyService.logNotification(
        makeNotification({
          channel: 'email',
          notificationType: 'order_confirmation',
          metadata: { userId: 'user-1' },
          sentAt: new Date('2026-01-15T00:00:00Z'),
        }),
      );
      historyService.logNotification(
        makeNotification({
          id: 'notif-0002',
          channel: 'webhook',
          notificationType: 'order_confirmation',
          metadata: { userId: 'user-1' },
          sentAt: new Date('2026-01-15T00:00:00Z'),
        }),
      );
      historyService.logNotification(
        makeNotification({
          id: 'notif-0003',
          channel: 'email',
          notificationType: 'order_status_update',
          metadata: { userId: 'user-1' },
          sentAt: new Date('2026-01-15T00:00:00Z'),
        }),
      );

      const results = historyService.query({
        userId: 'user-1',
        channel: 'email',
        notificationType: 'order_confirmation',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.id).toBe('nlog-0001');
    });
  });

  describe('getAll and getCount', () => {
    it('should return all entries', () => {
      historyService.logNotification(makeNotification());
      historyService.logNotification(makeNotification({ id: 'notif-0002' }));

      expect(historyService.getAll()).toHaveLength(2);
      expect(historyService.getCount()).toBe(2);
    });
  });
});

describe('NotificationService + NotificationHistoryService integration', () => {
  let db: Database;
  let eventBus: EventBus;
  let logRepo: NotificationLogRepository;
  let historyService: NotificationHistoryService;
  let notificationService: NotificationService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    logRepo = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(logRepo);
    notificationService = new NotificationService(eventBus, undefined, historyService);
    resetNotificationIdCounter();
    resetNotificationLogIdCounter();
  });

  it('should log notifications when events are emitted', async () => {
    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
        total: 20,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(historyService.getCount()).toBe(1);
    const entries = historyService.getAll();
    expect(entries[0]?.recipient).toBe('alice@example.com');
    expect(entries[0]?.channel).toBe('email');
    expect(entries[0]?.notificationType).toBe('order_confirmation');
    expect(entries[0]?.status).toBe('sent');
    expect(entries[0]?.metadata?.['orderId']).toBe('order-1');
    expect(entries[0]?.metadata?.['userId']).toBe('user-1');
  });

  it('should log multiple notifications from different events', async () => {
    await eventBus.emit({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    } satisfies OrderCreatedEvent);

    await eventBus.emit({
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 10,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    } satisfies OrderStatusChangedEvent);

    expect(historyService.getCount()).toBe(2);
    const byType = historyService.getByType('order_confirmation');
    expect(byType).toHaveLength(1);
    const statusUpdates = historyService.getByType('order_status_update');
    expect(statusUpdates).toHaveLength(1);
  });

  it('should update log entry status to failed when adapter fails', async () => {
    const failingTransport: InMemoryEmailTransport = {
      async send() {
        return { success: false, error: 'SMTP error' };
      },
      getSentEmails() {
        return [];
      },
      clearSentEmails() {},
    } as unknown as InMemoryEmailTransport;

    const failingAdapter = new EmailNotificationAdapter(undefined, failingTransport);
    notificationService.registerAdapter(failingAdapter);

    await eventBus.emit({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    } satisfies OrderCreatedEvent);

    // Wait for fire-and-forget adapter call
    await new Promise((r) => setTimeout(r, 10));

    const entries = historyService.getAll();
    expect(entries).toHaveLength(1);
    expect(entries[0]?.status).toBe('failed');
  });

  it('should be queryable by user after events are emitted', async () => {
    await eventBus.emit({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    } satisfies OrderCreatedEvent);

    expect(historyService.getByUser('user-1')).toHaveLength(1);
    expect(historyService.getByUser('user-2')).toHaveLength(0);
  });

  it('should work without history service (backwards compat)', async () => {
    const serviceWithoutHistory = new NotificationService(eventBus);

    await eventBus.emit({
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 10,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    } satisfies OrderStatusChangedEvent);

    expect(serviceWithoutHistory.getNotificationCount()).toBe(1);
  });
});

